/// Snapshot of a command's state for the frontend. The persistent REPL gives
/// each submitted command an id and persists its output/exit, so a fast command
/// that finishes before the UI subscribes is still fully recoverable by polling.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CommandSnapshot {
    pub id: String,
    pub command: String,
    pub status: String,
    pub created_at: String,
    pub exit_code: Option<i32>,
    pub output: String,
    pub duration_ms: Option<u64>,
}

/// Lightweight metadata we keep per command (id → command text + created_at),
/// since the REPL only stores output/done/exit_code.
#[derive(Clone)]
struct CommandMeta {
    command: String,
    created_at: String,
}

// Holds the live REPL behind an RwLock<Option<Arc<…>>> (not a OnceCell) so it
// can be swapped out by `interrupt_command` to recover from a wedged session.
#[cfg(not(mobile))]
static REPL: tokio::sync::RwLock<Option<Arc<PersistentRepl>>> =
    tokio::sync::RwLock::const_new(None);
#[cfg(not(mobile))]
static REPL_AGENT_GEN_TOKENS: tokio::sync::RwLock<Option<usize>> =
    tokio::sync::RwLock::const_new(None);

static COMMAND_META: std::sync::OnceLock<RwLock<HashMap<String, CommandMeta>>> =
    std::sync::OnceLock::new();
/// Preserve submission order for newest-first listing.
static COMMAND_ORDER: std::sync::OnceLock<RwLock<Vec<String>>> = std::sync::OnceLock::new();

fn command_meta() -> &'static RwLock<HashMap<String, CommandMeta>> {
    COMMAND_META.get_or_init(|| RwLock::new(HashMap::new()))
}
fn command_order() -> &'static RwLock<Vec<String>> {
    COMMAND_ORDER.get_or_init(|| RwLock::new(Vec::new()))
}

#[cfg(not(mobile))]
fn resolve_bin(env_var: &str, name: &str) -> Result<String, String> {
    use std::path::Path;
    // 1. Explicit override — but only when the path actually exists. Trusting a
    //    stale override is what turns a missing binary into an opaque
    //    "No such file or directory (os error 2)" at spawn time.
    if let Ok(b) = std::env::var(env_var) {
        if Path::new(&b).exists() {
            return Ok(b);
        }
        // Stale override: fall through to discovery instead of failing opaquely.
    }
    // 2. On PATH — set when the app is launched from a shell that sourced the
    //    repo's .bin (the common dev case).
    if let Ok(p) = which::which(name) {
        return Ok(p.to_string_lossy().to_string());
    }
    // 3. Bundled resource locations. Packaged apps should be self-contained and
    // not depend on a checkout next to the .app.
    for cand in bundled_bin_candidates(name) {
        if cand.exists() {
            return Ok(cand.to_string_lossy().to_string());
        }
    }
    // 4. Known repo locations. A GUI app launched from Finder/Dock has a minimal
    //    PATH (/usr/bin:/bin:...) that does NOT include open-source/.bin, so PATH
    //    lookup fails there; resolve against the monorepo layout instead.
    if let Some(root) = Path::new(env!("CARGO_MANIFEST_DIR")).ancestors().nth(3) {
        // src-tauri -> moonshine-tauri -> gnosis -> open-source
        for cand in [
            root.join(".bin").join(name),
            root.join("gnosis/monster-guard/target/release").join(name),
            root.join("gnosis/moonshine/target/release").join(name),
        ] {
            if cand.exists() {
                return Ok(cand.to_string_lossy().to_string());
            }
        }
    }
    Err(format!(
        "{name}: not found via ${env_var}, PATH, bundled resources, or repo .bin — build it with a0 or set {env_var} to its full path"
    ))
}

#[cfg(not(mobile))]
fn bundled_bin_candidates(name: &str) -> Vec<std::path::PathBuf> {
    let mut out = Vec::new();
    let exe = match std::env::current_exe() {
        Ok(path) => path,
        Err(_) => return out,
    };
    if let Some(exe_dir) = exe.parent() {
        // macOS bundle: Contents/MacOS/<app> -> Contents/Resources/binaries/<name>
        out.push(exe_dir.join("../Resources/binaries").join(name));
        // Linux bundle layouts vary by target; keep common adjacent resource
        // paths before falling back to repo-local development paths.
        out.push(exe_dir.join("binaries").join(name));
        out.push(exe_dir.join("../lib").join(name));
        out.push(exe_dir.join(name));
    }
    out
}

#[cfg(not(mobile))]
fn guard_home() -> String {
    std::env::var("MONSTER_GUARD_HOME").unwrap_or_else(|_| {
        home::home_dir()
            .map(|h| h.join(".moonshine.d").to_string_lossy().to_string())
            .unwrap_or_else(|| ".moonshine.d".to_string())
    })
}

#[cfg(not(mobile))]
fn normalize_agent_gen_tokens(agent_gen_tokens: Option<usize>) -> Option<usize> {
    agent_gen_tokens
        .filter(|tokens| *tokens > 0)
        .map(|tokens| tokens.clamp(1, 4096))
}

#[cfg(not(mobile))]
fn apply_agent_gen_tokens_env(agent_gen_tokens: Option<usize>) {
    if let Some(tokens) = normalize_agent_gen_tokens(agent_gen_tokens) {
        std::env::set_var("MOONSHINE_AGENT_GEN_TOKENS", tokens.to_string());
    }
}

#[cfg(not(mobile))]
fn default_workdir() -> PathBuf {
    home::home_dir()
        .or_else(|| std::env::current_dir().ok())
        .unwrap_or_else(|| PathBuf::from("/"))
}

#[cfg(not(mobile))]
fn resolve_workdir(cwd: Option<String>) -> PathBuf {
    let Some(raw) = cwd else {
        return default_workdir();
    };
    let trimmed = raw.trim();
    if trimmed.is_empty() || trimmed == "/" {
        return default_workdir();
    }

    let expanded = if trimmed == "~" {
        home::home_dir().unwrap_or_else(default_workdir)
    } else if let Some(rest) = trimmed.strip_prefix("~/") {
        home::home_dir().unwrap_or_else(default_workdir).join(rest)
    } else {
        PathBuf::from(trimmed)
    };

    if expanded.is_dir() {
        expanded
    } else {
        default_workdir()
    }
}

#[cfg(not(mobile))]
async fn prepare_repl_agent_gen_tokens(
    agent_gen_tokens: Option<usize>,
    app: &tauri::AppHandle,
) -> Result<(), String> {
    let normalized = normalize_agent_gen_tokens(agent_gen_tokens);
    apply_agent_gen_tokens_env(normalized);

    let mut current = REPL_AGENT_GEN_TOKENS.write().await;
    if *current == normalized {
        return Ok(());
    }
    *current = normalized;

    let mut repl = REPL.write().await;
    if let Some(old) = repl.as_ref() {
        let guard = resolve_bin("MONSTER_GUARD_BIN", "monster-guard")?;
        let moon = resolve_bin("MOONSHINE_BIN", "moonshine")?;
        let home = guard_home();
        let fresh = old
            .restart(&guard, &home, &moon, app.clone())
            .await
            .map_err(|e| format!("Failed to restart moonshine REPL: {}", e))?;
        *repl = Some(Arc::new(fresh));
    }
    Ok(())
}

#[cfg(not(mobile))]
async fn get_or_init_repl(app: &tauri::AppHandle) -> Result<Arc<PersistentRepl>, String> {
    // Fast path: already initialized.
    if let Some(repl) = REPL.read().await.as_ref() {
        return Ok(repl.clone());
    }
    // Slow path: take the write lock and double-check (another task may have
    // initialized it while we waited).
    let mut w = REPL.write().await;
    if let Some(repl) = w.as_ref() {
        return Ok(repl.clone());
    }
    let guard = resolve_bin("MONSTER_GUARD_BIN", "monster-guard")?;
    let moon = resolve_bin("MOONSHINE_BIN", "moonshine")?;
    let home = guard_home();
    let repl = Arc::new(
        PersistentRepl::spawn(&guard, &home, &moon, app.clone())
            .await
            .map_err(|e| format!("Failed to start moonshine REPL: {}", e))?,
    );
    *w = Some(repl.clone());
    Ok(repl)
}

/// Interrupt a wedged REPL: tear down the current moonshine process and replace
/// it with a fresh one (command history is preserved; any still-running command
/// is marked interrupted, exit 130). This is the recovery path for a
/// non-interactive command that never returns and so blocks moonshine itself —
/// the persistent REPL serializes commands, so without this one hung command
/// would wedge the whole terminal.
#[cfg(not(mobile))]
#[tauri::command]
async fn interrupt_command(app: tauri::AppHandle) -> Result<(), String> {
    let mut w = REPL.write().await;
    let guard = resolve_bin("MONSTER_GUARD_BIN", "monster-guard")?;
    let moon = resolve_bin("MOONSHINE_BIN", "moonshine")?;
    let home = guard_home();
    let fresh = match w.as_ref() {
        Some(old) => old
            .restart(&guard, &home, &moon, app.clone())
            .await
            .map_err(|e| format!("Failed to restart moonshine REPL: {}", e))?,
        // Nothing running yet — just start one.
        None => PersistentRepl::spawn(&guard, &home, &moon, app.clone())
            .await
            .map_err(|e| format!("Failed to start moonshine REPL: {}", e))?,
    };
    *w = Some(Arc::new(fresh));
    Ok(())
}

/// Submit a command to the persistent guarded moonshine REPL.
#[cfg(not(mobile))]
#[tauri::command]
async fn spawn_shell(
    command: String,
    agent_gen_tokens: Option<usize>,
    app: tauri::AppHandle,
) -> Result<CommandSnapshot, String> {
    AdmissionGate::new()
        .verify_admission()
        .await
        .map_err(|e| format!("Admission denied: {}", e))?;

    prepare_repl_agent_gen_tokens(agent_gen_tokens, &app).await?;
    let repl = get_or_init_repl(&app).await?;
    let id = repl
        .submit(&command, &app)
        .await
        .map_err(|e| format!("Failed to submit command: {}", e))?;

    let created_at = chrono::Local::now().to_rfc3339();
    command_meta().write().await.insert(
        id.clone(),
        CommandMeta { command: command.clone(), created_at: created_at.clone() },
    );
    command_order().write().await.push(id.clone());

    Ok(CommandSnapshot {
        id,
        command,
        status: "running".to_string(),
        created_at,
        exit_code: None,
        output: String::new(),
        duration_ms: None,
    })
}

/// Prompt context: the working directory + current git branch (if any).
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct ReplContext {
    pub cwd: String,
    pub branch: String,
}

/// Run a command on the REPL (without registering it in the process list) and
/// return its full output, polling briefly for completion. Used for the prompt
/// context queries (pwd, git branch) which are instant on the warm REPL.
#[cfg(not(mobile))]
async fn repl_run_output(repl: &PersistentRepl, cmd: &str, app: &tauri::AppHandle) -> String {
    let id = match repl.submit(cmd, app).await {
        Ok(i) => i,
        Err(_) => return String::new(),
    };
    for _ in 0..40 {
        if let Some((output, done, _exit, _ms)) = repl.get_state(&id).await {
            if done {
                return output;
            }
        }
        tokio::time::sleep(std::time::Duration::from_millis(15)).await;
    }
    String::new()
}

/// Query the REPL's working directory and git branch (without registering them
/// in the process list), so the prompt shows a real cwd that tracks `cd` plus
/// the branch like any good shell prompt. Both degrade to empty on failure
/// (e.g. not a git repo → no branch). Verified: the guarded REPL passes `--`
/// flags through correctly, so `git rev-parse --abbrev-ref HEAD` returns the
/// branch.
#[cfg(not(mobile))]
#[tauri::command]
async fn repl_cwd(
    agent_gen_tokens: Option<usize>,
    app: tauri::AppHandle,
) -> Result<ReplContext, String> {
    if prepare_repl_agent_gen_tokens(agent_gen_tokens, &app)
        .await
        .is_err()
    {
        return Ok(ReplContext::default());
    }
    let repl = match get_or_init_repl(&app).await {
        Ok(r) => r,
        Err(_) => return Ok(ReplContext::default()),
    };
    let pwd_out = repl_run_output(&repl, "pwd", &app).await;
    let cwd = pwd_out
        .lines()
        .rev()
        .map(|l| l.trim())
        .find(|l| l.starts_with('/'))
        .unwrap_or("")
        .to_string();
    let cwd = if cwd.trim_matches('/').is_empty() {
        String::new()
    } else {
        cwd
    };
    // NB: no `2>/dev/null` — moonshine mishandles stderr redirects (the command
    // then yields no stdout). git's "fatal: not a git repository" error lands on
    // stderr (which the REPL captures into the same output), so we instead
    // recognise a real branch line: non-empty, single token, not a path, and not
    // a git diagnostic. Non-repos → no match → empty branch.
    let br_out = repl_run_output(&repl, "git rev-parse --abbrev-ref HEAD", &app).await;
    let branch = br_out
        .lines()
        .map(|l| l.trim())
        .rfind(|l| {
            !l.is_empty()
                && !l.contains(' ')
                && !l.starts_with('/')
                && !l.starts_with("fatal")
                && !l.starts_with("warning")
                && !l.starts_with("error")
        })
        .unwrap_or("")
        .to_string();
    Ok(ReplContext { cwd, branch })
}

#[cfg(not(mobile))]
async fn snapshot_for(id: &str) -> Option<CommandSnapshot> {
    let meta = command_meta().read().await;
    let m = meta.get(id)?.clone();
    let repl = REPL.read().await.clone();
    let (output, done, exit_code, duration_ms) = match repl {
        Some(r) => r.get_state(id).await.unwrap_or_default(),
        None => (String::new(), false, None, None),
    };
    Some(CommandSnapshot {
        id: id.to_string(),
        command: m.command,
        status: if done { "completed".to_string() } else { "running".to_string() },
        created_at: m.created_at,
        exit_code,
        output,
        duration_ms,
    })
}

#[cfg(not(mobile))]
#[tauri::command]
async fn get_process(process_id: String) -> Result<CommandSnapshot, String> {
    snapshot_for(&process_id)
        .await
        .ok_or_else(|| format!("Command {} not found", process_id))
}

#[cfg(not(mobile))]
#[tauri::command]
async fn list_processes() -> Result<Vec<CommandSnapshot>, String> {
    let order = command_order().read().await.clone();
    let mut out = Vec::with_capacity(order.len());
    // Newest first.
    for id in order.iter().rev() {
        if let Some(s) = snapshot_for(id).await {
            out.push(s);
        }
    }
    Ok(out)
}

/// Kill is a no-op stub in the persistent model (commands are short-lived REPL
