#[cfg(not(mobile))]
fn active_model_id(config: &LocalModelConfig, manifest: &[ModelManifestEntry]) -> String {
    let fallback = manifest
        .first()
        .map(|m| m.id)
        .unwrap_or("qwen2.5-0.5b-instruct-q4");
    config
        .active_model_id
        .as_deref()
        .filter(|id| manifest.iter().any(|m| m.id == *id))
        .unwrap_or(fallback)
        .to_string()
}

#[cfg(not(mobile))]
fn model_url(model: &ModelManifestEntry, config: &LocalModelConfig) -> String {
    config
        .url_overrides
        .get(model.id)
        .filter(|url| !url.trim().is_empty())
        .cloned()
        .or_else(|| std::env::var(model.env_url).ok().filter(|url| !url.trim().is_empty()))
        .unwrap_or_else(|| model.url.to_string())
}

#[cfg(not(mobile))]
fn model_snapshot(
    model: &ModelManifestEntry,
    config: &LocalModelConfig,
    active_id: &str,
) -> ModelSnapshot {
    let cache_path = model_cache_dir().join(model.cache_name);
    let meta = std::fs::metadata(&cache_path).ok().filter(|m| m.is_file());
    ModelSnapshot {
        id: model.id.to_string(),
        label: model.label.to_string(),
        url: model_url(model, config),
        cache_path: cache_path.to_string_lossy().to_string(),
        present: meta.is_some(),
        size_bytes: meta.map(|m| m.len()),
        active: model.id == active_id,
    }
}

#[cfg(not(mobile))]
#[tauri::command]
async fn model_status() -> Result<ModelStatus, String> {
    let manifest = model_manifest();
    let config = read_model_config();
    let active_id = active_model_id(&config, &manifest);
    Ok(ModelStatus {
        active_model_id: active_id.clone(),
        cache_dir: model_cache_dir().to_string_lossy().to_string(),
        models: manifest
            .iter()
            .map(|model| model_snapshot(model, &config, &active_id))
            .collect(),
    })
}

#[cfg(not(mobile))]
#[tauri::command]
async fn configure_model(model_id: String, url: Option<String>) -> Result<ModelSnapshot, String> {
    let manifest = model_manifest();
    let model = manifest
        .iter()
        .find(|model| model.id == model_id)
        .or_else(|| manifest.first())
        .ok_or_else(|| "model manifest is empty".to_string())?;
    let mut config = read_model_config();
    config.active_model_id = Some(model.id.to_string());
    if let Some(url) = url {
        let trimmed = url.trim();
        if trimmed.is_empty() {
            config.url_overrides.remove(model.id);
        } else {
            config
                .url_overrides
                .insert(model.id.to_string(), trimmed.to_string());
        }
    }
    write_model_config(&config)?;
    Ok(model_snapshot(model, &config, model.id))
}

#[cfg(not(mobile))]
#[tauri::command]
async fn download_model(model_id: Option<String>) -> Result<ModelSnapshot, String> {
    use reqwest::header::RANGE;
    use tokio::io::AsyncWriteExt;

    let manifest = model_manifest();
    let mut config = read_model_config();
    let active_id = active_model_id(&config, &manifest);
    let target_id = model_id.unwrap_or(active_id);
    let model = manifest
        .iter()
        .find(|model| model.id == target_id)
        .or_else(|| manifest.first())
        .ok_or_else(|| "model manifest is empty".to_string())?;
    let url = model_url(model, &config);
    let cache_dir = model_cache_dir();
    tokio::fs::create_dir_all(&cache_dir)
        .await
        .map_err(|e| format!("model cache dir: {e}"))?;
    let dest = cache_dir.join(model.cache_name);
    let partial = cache_dir.join(format!("{}.partial", model.cache_name));
    let existing = tokio::fs::metadata(&partial).await.map(|m| m.len()).unwrap_or(0);

    let client = reqwest::Client::new();
    let mut request = client.get(&url);
    if existing > 0 {
        request = request.header(RANGE, format!("bytes={existing}-"));
    }
    let mut response = request
        .send()
        .await
        .map_err(|e| format!("model download request: {e}"))?;
    if !response.status().is_success() {
        return Err(format!("model download failed: {} from {url}", response.status()));
    }
    let resumed = existing > 0 && response.status() == reqwest::StatusCode::PARTIAL_CONTENT;
    if existing > 0 && !resumed {
        let _ = tokio::fs::remove_file(&partial).await;
    }
    let mut file = tokio::fs::OpenOptions::new()
        .create(true)
        .append(resumed)
        .write(true)
        .truncate(!resumed)
        .open(&partial)
        .await
        .map_err(|e| format!("model partial open: {e}"))?;
    while let Some(chunk) = response
        .chunk()
        .await
        .map_err(|e| format!("model download chunk: {e}"))?
    {
        file.write_all(&chunk)
            .await
            .map_err(|e| format!("model partial write: {e}"))?;
    }
    file.flush()
        .await
        .map_err(|e| format!("model partial flush: {e}"))?;
    tokio::fs::rename(&partial, &dest)
        .await
        .map_err(|e| format!("model cache finalize: {e}"))?;

    config.active_model_id = Some(model.id.to_string());
    write_model_config(&config)?;
    Ok(model_snapshot(model, &config, model.id))
}

