#[cfg(not(mobile))]
#[tauri::command]
async fn system_info() -> Result<SystemInfo, String> {
    let moonshine_bin = resolve_bin("MOONSHINE_BIN", "moonshine")
        .unwrap_or_else(|_| "(not found)".to_string());
    let guard_bin = resolve_bin("MONSTER_GUARD_BIN", "monster-guard")
        .unwrap_or_else(|_| "(not found)".to_string());
    let home = guard_home();

    // Identity: ~/.moonshine.knot / .json / dir, mirroring the admission gate.
    let home_dir = home::home_dir();
    let (identity_present, identity_path) = home_dir
        .as_ref()
        .map(|h| {
            for marker in [".moonshine.knot", ".moonshine.json", ".moonshine"] {
                let p = h.join(marker);
                if p.exists() {
                    return (true, p.to_string_lossy().to_string());
                }
            }
            (false, String::new())
        })
        .unwrap_or((false, String::new()));

    let grants_count = std::fs::read_dir(format!("{}/grants", home))
        .map(|rd| rd.flatten().count())
        .unwrap_or(0);
    let mut problems = Vec::new();
    if moonshine_bin == "(not found)" {
        problems.push("moonshine runtime binary not found".to_string());
    }
    if guard_bin == "(not found)" {
        problems.push("monster-guard runtime binary not found".to_string());
    }
    if !identity_present && std::env::var("FAT_STATION_PORT").is_err() {
        problems.push("no moonshine identity marker or FAT_STATION_PORT admission".to_string());
    }
    if std::fs::create_dir_all(&home).is_err() {
        problems.push(format!("guard home is not writable: {home}"));
    }
    let ready = problems.is_empty();

    Ok(SystemInfo {
        moonshine_bin,
        guard_bin,
        guard_home: home,
        identity_present,
        identity_path,
        grants_count,
        repl_active: REPL.read().await.is_some(),
        ready,
        problems,
    })
}

