/// Spawn a VM console (e.g. `boot-iso <iso>`) in a PTY tab — guard-free, since a
/// booted VM is the faithful/opaque rung (the VZ bridge needs real virtualization
/// syscalls). The braid certificate is enforced downstream by boot-iso → swerve.
#[cfg(not(mobile))]
#[tauri::command]
async fn spawn_vm(
    command: String,
    cols: u16,
    rows: u16,
    cwd: Option<String>,
    app: tauri::AppHandle,
) -> Result<String, String> {
    AdmissionGate::new()
        .verify_admission()
        .await
        .map_err(|e| format!("Admission denied: {}", e))?;
    let cwd = resolve_workdir(cwd);
    pty_session::spawn_vm(&command, cols, rows, &cwd, app)
        .map_err(|e| format!("Failed to start VM: {}", e))
}

/// Open a URL in the system browser (used for the card.yoga sign-in handoff).
/// Restricted to https card.yoga / localhost origins so a compromised frontend
/// can't turn this into an arbitrary launcher.
#[cfg(not(mobile))]
#[tauri::command]
async fn open_url(url: String) -> Result<(), String> {
    let ok = url.starts_with("https://card.yoga/")
        || url.starts_with("https://accounts.google.com/")
        || url.starts_with("https://github.com/login")
        || url.starts_with("https://appleid.apple.com/")
        || url.starts_with("https://discord.com/")
        || url.starts_with("http://localhost:")
        || url.starts_with("http://127.0.0.1:");
    if !ok {
        return Err("refused: only card.yoga / known OAuth origins may be opened".into());
    }
    let prog = if cfg!(target_os = "macos") { "open" } else { "xdg-open" };
    std::process::Command::new(prog)
        .arg(&url)
        .spawn()
        .map(|_| ())
        .map_err(|e| format!("failed to open browser: {e}"))
}

#[cfg(mobile)]
fn mobile_unavailable(feature: &str) -> String {
    format!("{feature} is not available in the mobile Moonshine shell build")
}

#[cfg(mobile)]
fn mobile_command_output(command: &str) -> String {
    let fat = mobile_bundled_bin("fat-station");
    let fat_status = match fat {
        Some(path) => format!("bundled fat-station asset: {path}"),
        None => "bundled fat-station asset: missing".to_string(),
    };
    format!(
        "Moonshine mobile kept this command local; no LAN bridge was used.\n\
         command: {command}\n\
         {fat_status}\n\n\
         The current bundled fat-station is a macOS arm64 executable asset, not an iOS-linked runtime. \
         iOS cannot use the Android/R1 ProcessBuilder sidecar model; the next native step is linking \
         distributed-inference/fat-client as an iOS static library inside the Tauri process.\n"
    )
}

#[cfg(mobile)]
async fn mobile_bridge_spawn(
    command: String,
    config: &MobileBridgeConfig,
) -> Result<CommandSnapshot, String> {
    let url = format!("{}/spawn_shell", config.url.trim().trim_end_matches('/'));
    let client = reqwest::Client::new();
    let mut request = client
        .post(&url)
        .json(&serde_json::json!({ "command": command }));
    if let Some(token) = config
        .token
        .as_deref()
        .map(str::trim)
        .filter(|token| !token.is_empty())
    {
        request = request.bearer_auth(token);
    }

    let response = request
        .send()
        .await
        .map_err(|e| format!("mobile Moonshine bridge unreachable at {url}: {e}"))?;
    let status = response.status();
    let text = response
        .text()
        .await
        .map_err(|e| format!("mobile Moonshine bridge response read failed at {url}: {e}"))?;
    if !status.is_success() {
        return Err(format!(
            "mobile Moonshine bridge rejected command at {url}: HTTP {status}: {text}"
        ));
    }
    serde_json::from_str::<CommandSnapshot>(&text)
        .map_err(|e| format!("mobile Moonshine bridge returned invalid process snapshot: {e}: {text}"))
}

#[cfg(mobile)]
fn mobile_bundled_bin(name: &str) -> Option<String> {
    let exe = std::env::current_exe().ok()?;
    let exe_dir = exe.parent()?;
    for candidate in [
        exe_dir.join("assets").join("binaries").join(name),
        exe_dir.join("../assets").join("binaries").join(name),
        exe_dir.join("binaries").join(name),
    ] {
        if candidate.exists() {
            return Some(candidate.to_string_lossy().to_string());
        }
    }
    None
}

