#[cfg(mobile)]
fn mobile_model_snapshot(model_id: &str, url: Option<String>) -> ModelSnapshot {
    let mut snapshots = mobile_model_snapshots(model_id);
    let mut snapshot = snapshots
        .drain(..)
        .find(|model| model.id == model_id)
        .or_else(|| mobile_model_snapshots("qwen2.5-0.5b-instruct-q4").into_iter().next())
        .unwrap_or_else(|| ModelSnapshot {
            id: model_id.to_string(),
            label: model_id.to_string(),
            url: String::new(),
            cache_path: String::new(),
            present: false,
            size_bytes: None,
            active: true,
        });
    snapshot.active = true;
    if let Some(url) = url.filter(|url| !url.trim().is_empty()) {
        snapshot.url = url;
    }
    snapshot
}

