#[cfg(mobile)]
async fn mobile_snapshot_for(id: &str) -> Option<CommandSnapshot> {
    let meta = command_meta().read().await.get(id).cloned()?;
    let output = mobile_command_output(&meta.command);
    Some(CommandSnapshot {
        id: id.to_string(),
        command: meta.command,
        status: "completed".to_string(),
        created_at: meta.created_at,
        exit_code: Some(0),
        output,
        duration_ms: Some(0),
    })
}

