#[cfg(mobile)]
#[tauri::command]
async fn spawn_shell(
    command: String,
    _agent_gen_tokens: Option<usize>,
    _app: tauri::AppHandle,
) -> Result<CommandSnapshot, String> {
    let bridge = read_mobile_bridge_config();
    if bridge.enabled && !bridge.url.trim().is_empty() {
        match mobile_bridge_spawn(command.clone(), &bridge).await {
            Ok(snapshot) => {
                command_meta().write().await.insert(
                    snapshot.id.clone(),
                    CommandMeta {
                        command: snapshot.command.clone(),
                        created_at: snapshot.created_at.clone(),
                    },
                );
                command_order().write().await.push(snapshot.id.clone());
                return Ok(snapshot);
            }
            Err(error) => {
                let mut next = bridge;
                next.last_error = Some(error.clone());
                let _ = write_mobile_bridge_config(&next);
                return Err(error);
            }
        }
    }

    let id = format!("mobile-{}", chrono::Utc::now().timestamp_millis());
    let created_at = chrono::Utc::now().to_rfc3339();
    command_meta().write().await.insert(
        id.clone(),
        CommandMeta {
            command: command.clone(),
            created_at: created_at.clone(),
        },
    );
    command_order().write().await.push(id.clone());
    Ok(CommandSnapshot {
        id: id.clone(),
        command: command.clone(),
        status: "completed".to_string(),
        created_at,
        exit_code: Some(0),
        output: mobile_command_output(&command),
        duration_ms: Some(0),
    })
}

