/// Bridge WebView console/errors to the host's stderr. The Tauri WebView's
/// console isn't piped anywhere by default, which makes blind debugging of
/// renderer issues (e.g. xterm.js) impossible. The frontend forwards
/// window.onerror + console.error/warn here so they show up when the app is
/// launched from a terminal. Cheap and reusable for any future WebView bug.
#[tauri::command]
fn js_log(level: String, msg: String) {
    eprintln!("[webview:{level}] {msg}");
}

#[cfg(not(target_os = "android"))]
fn emit_deep_link_event(app: &tauri::AppHandle, links: &[String]) {
    if links.is_empty() {
        return;
    }
    let payload = if links.len() == 1 {
        serde_json::json!({ "uri": links[0] })
    } else {
        serde_json::json!({ "uri": links })
    };
    app.emit("moonshine://deep-link", payload).ok();
}

#[cfg(not(mobile))]
fn extract_moonshine_links(argv: &[String]) -> Vec<String> {
    argv.iter()
        .filter(|arg| arg.starts_with("moonshine://"))
        .cloned()
        .collect()
}

/// Emit an `open-iso` event for `.iso`/`.img` paths the OS asked us to open
/// (Finder "Open With", a launch arg, or a second-instance arg) so the frontend
/// boots each as a VM tab.
fn emit_open_iso(app: &tauri::AppHandle, paths: &[String]) {
    if paths.is_empty() {
        return;
    }
    app.emit("open-iso", serde_json::json!({ "paths": paths })).ok();
}

/// Pull bootable ISO targets out of argv / opened URLs: local `.iso`/`.img` files
/// (`file://` and `%20` normalized), `http(s)://` ISO URLs, and `aeon://iso/<id>`
/// sovereign addresses (the frontend resolves those to a CDN URL). Other
/// `aeon://` deep links are left for normal handling.
#[cfg(not(mobile))]
fn extract_iso_paths(items: &[String]) -> Vec<String> {
    items
        .iter()
        .filter_map(|raw| {
            let s = raw.trim();
            if s.starts_with("aeon://iso/") {
                return Some(s.to_string());
            }
            let low = s.to_ascii_lowercase();
            if (s.starts_with("http://") || s.starts_with("https://"))
                && (low.ends_with(".iso") || low.ends_with(".img"))
            {
                return Some(s.to_string());
            }
            let p = s.strip_prefix("file://").unwrap_or(s);
            let plow = p.to_ascii_lowercase();
            if plow.ends_with(".iso") || plow.ends_with(".img") {
                Some(p.replace("%20", " "))
            } else {
                None
            }
        })
        .collect()
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    let builder = tauri::Builder::default();

    #[cfg(not(mobile))]
    let builder = builder.plugin(tauri_plugin_single_instance::init(|app, argv, _cwd| {
        let links = extract_moonshine_links(&argv);
        emit_deep_link_event(app, &links);
        emit_open_iso(app, &extract_iso_paths(&argv));
    }));

    let app = builder
        .plugin(tauri_plugin_deep_link::init())
        .plugin(tauri_plugin_shell::init())
        .plugin(tauri_plugin_store::Builder::default().build())
        .setup(|_app| {
            #[cfg(not(mobile))]
            {
                let argv: Vec<String> = std::env::args().collect();
                let links = extract_moonshine_links(&argv);
                emit_deep_link_event(_app.handle(), &links);
                emit_open_iso(_app.handle(), &extract_iso_paths(&argv));
            }
            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            spawn_shell,
            kill_process,
            list_processes,
            get_process,
            system_info,
            model_status,
            configure_model,
            download_model,
            skymesh_status,
            configure_skymesh,
            mobile_bridge_status,
            configure_mobile_bridge,
            list_admissions,
            delegate_admission,
            revoke_admission,
            remove_admission,
            open_url,
            complete,
            browse,
            repl_cwd,
            spawn_pty,
            spawn_vm,
            pty_write,
            pty_resize,
            pty_kill,
            pty_buffer,
            js_log,
            interrupt_command,
            clear_history,
        ])
        .build(tauri::generate_context!())
        .expect("error while building moonshine-tauri");

    #[cfg(any(target_os = "macos", target_os = "ios"))]
    app.run(|app_handle, event| {
        if let tauri::RunEvent::Opened { urls } = &event {
            let strs: Vec<String> = urls.iter().map(|url| url.to_string()).collect();
            // A `.iso`/`.img` opened from Finder ("Open With → Moonshine") boots
            // as a VM tab; `moonshine://` URLs stay deep links.
            emit_open_iso(app_handle, &extract_iso_paths(&strs));
            let links: Vec<String> = strs
                .iter()
                .filter(|s| s.starts_with("moonshine://"))
                .cloned()
                .collect();
            emit_deep_link_event(app_handle, &links);
        }
    });

    #[cfg(not(any(target_os = "macos", target_os = "ios")))]
    app.run(|_app_handle, _event| {});
}
